# Category: serverless_security

import boto3
import logging
from PIL import Image
import io

# Initialize clients
s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

# IAM Role Definition (Commented out for reference)
# {
#     "Version": "2012-10-17",
#     "Statement": [
#         {
#             "Effect": "Allow",
#             "Action": [
#                 "s3:GetObject",
#                 "s3:PutObject"
#             ],
#             "Resource": "*"
#         },
#         {
#             "Effect": "Allow",
#             "Action": "sns:Publish",
#             "Resource": "*"
#         }
#     ]
# }

def lambda_handler(event, context):
    # Set up logging
    logger = logging.getLogger()
    logger.setLevel(logging.INFO)

    try:
        # Get bucket name and key from the Lambda event
        bucket_name = event['Records'][0]['s3']['bucket']['name']
        key = event['Records'][0]['s3']['object']['key']

        # Read image from S3
        response = s3_client.get_object(Bucket=bucket_name, Key=key)
        image_content = response['Body'].read()

        # Open and process the image (example: convert to grayscale)
        with Image.open(io.BytesIO(image_content)) as img:
            gray_img = img.convert('L')

            # Save processed image to a buffer
            output_buffer = io.BytesIO()
            gray_img.save(output_buffer, format=img.format)
            output_buffer.seek(0)

            # Write processed image back to S3
            s3_client.put_object(Bucket=bucket_name, Key=f'processed-{key}', Body=output_buffer)

        # Send notification via SNS
        sns_client.publish(
            TopicArn='arn:aws:sns:REGION:ACCOUNT_ID:TOPIC_NAME',
            Message=f'Image processed successfully: {key}'
        )

        logger.info(f'Processed image saved to S3: s3://{bucket_name}/processed-{key}')

    except Exception as e:
        logger.error(f'Error processing image: {str(e)}')